#define ct_dd_audio_print(arg)		if(gCt_DD_Audio_Display_Flag) {Ddim_Print(arg);}

#define ct_dd_audio_test_assert(_a) \
    {\
        if (! _a) {\
            Ddim_Print(("%d:            ct_dd_audio_test_assert: TestCaseError(0x%08x)\n", __LINE__, _a));\
            ct_dd_audio_do_test_ng_countup();\
        } else {\
            ct_dd_audio_do_test_ok_countup();\
        }\
    }

#define ct_dd_audio_test_assert_equals(_a, _b) \
    {\
        if (_a != _b) {\
            Ddim_Print(("%d:     ct_dd_audio_test_assert_equals: TestCaseError(0x%08x, 0x%08x)\n", __LINE__, _a, _b));\
            ct_dd_audio_do_test_ng_countup();\
        } else {\
            ct_dd_audio_do_test_ok_countup();\
        }\
    }

#define ct_dd_audio_test_assert_not_equals(_a, _b) \
    {\
        if (_a == _b) {\
            Ddim_Print(("%d: ct_dd_audio_test_assert_not_equals: TestCaseError(0x%08x, 0x%08x)\n", __LINE__, _a, _b));\
            ct_dd_audio_do_test_ng_countup();\
        } else {\
            ct_dd_audio_do_test_ok_countup();\
        }\
    }


