VOID CT_Dd_Audio_Int_HandlerTest19( UINT8 ch )
{
	T_DD_AUDIO_I2S_CMMN i2s_common;
	T_DD_AUDIO_I2S_OUT i2s_out;
	T_DD_AUDIO_CTRL_OUT ctrl_inf;
	T_DD_AUDIO_CTRL_COMMON ctrl_common;

	Ddim_Print(( "<%s> Start\n", __FUNCTION__ ));

#ifdef PC_DEBUG
	IO_CHIPTOP.PLLCNT1.bit.PL10ST = 1;
	IO_AUDIO.AUDIOIF[ch].AUOFST.word = 0xFFFFFFFF;
#endif

	DDIM_User_DisableInt((DDIM_USER_INTID)(E_DD_GIC_INTID_AUDIO_IF_CH0_INT + ch));

	Dd_Audio_Init();

	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	ctrl_common.fifo_usage = E_DD_AUDIO_FIFO_USAGE_STAGES_16;
	Dd_Audio_Ctrl_Common(ch, &ctrl_common);

	Dd_Audio_Get_Ctrl_Output(ch, &ctrl_inf);

	ctrl_inf.format = E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
	ctrl_inf.fifo_stages = E_DD_AUDIO_FIFO_STAGES_1;
	ctrl_inf.ahb_format = E_DD_AUDIO_AHB_FRMT_R_JUST;
	ctrl_inf.lr_copy = 0;
	ctrl_inf.mix_play = 0;
	ctrl_inf.bit_shift = E_DD_AUDIO_BIT_SHIFT_0;
	(VOID)Dd_Audio_Ctrl_Output(ch, &ctrl_inf);

	if (ch != 1){
		Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
		i2s_common.master_slave = E_DD_AUDIO_CLK_MASTER;
		i2s_common.clk_div_enable = D_DD_AUDIO_ENABLE;
		Dd_Audio_Ctrl_I2sCmmn(ch, &i2s_common);
	}
	else {
		Dd_Audio_Get_Ctrl_I2sCmmn(0, &i2s_common);
		i2s_common.master_slave = E_DD_AUDIO_CLK_MASTER;
		i2s_common.clk_div_enable = D_DD_AUDIO_ENABLE;
		Dd_Audio_Ctrl_I2sCmmn(0, &i2s_common);
	}

	Dd_Audio_Get_Ctrl_I2sOut(ch, &i2s_out);
	i2s_out.bit_out = E_DD_AUDIO_BIT_24BIT;
	i2s_out.mode_out = E_DD_AUDIO_MODE_I2S;
	i2s_out.fs = E_DD_AUDIO_FS_64FS;
	Dd_Audio_Ctrl_I2sOut(ch, &i2s_out);

	if (ch != 1){
		IO_AUDIO.AUDIOIF[ch].AUODLR = 1;
		
		Dd_Audio_Start_Output(ch);
	}
	else {
		IO_AUDIO.AUDIOIF[0].AUODLR = 1;
		IO_AUDIO.AUDIOIF[1].AUODLR = 1;
		
		Dd_Audio_Start_Output(D_DD_AUDIO_IF_CH0_CH1);
	}
	
	DDIM_User_Dly_Tsk(1);

	Ddim_Print(("AUOEF = %d\n", IO_AUDIO.AUDIOIF[ch].AUCR.bit.AUOEF));

	IO_AUDIO.AUDIOIF[ch].AUCR.bit.INTIE = 0;
	IO_AUDIO.AUDIOIF[ch].AUCR.bit.INTI = 0;
	
	IO_AUDIO.AUDIOIF[ch].AUST.bit.EINTIE = 0;
	IO_AUDIO.AUDIOIF[ch].AUST.bit.EINTI = 0;

	IO_AUDIO.AUDIOIF[ch].AUST.bit.OFIE = 0;
	IO_AUDIO.AUDIOIF[ch].AUST.bit.IROF = 0;

	IO_AUDIO.AUDIOIF[ch].AUCR.bit.INTOE = 0;
	IO_AUDIO.AUDIOIF[ch].AUCR.bit.INTO = 0;

	IO_AUDIO.AUDIOIF[ch].AUST.bit.EINTOE = 0;
	IO_AUDIO.AUDIOIF[ch].AUST.bit.EINTO = 0;

	IO_AUDIO.AUDIOIF[ch].AUST.bit.UFIE = 1;
	IO_AUDIO.AUDIOIF[ch].AUST.bit.ORUF = 1;

	Dd_Audio_Int_Handler(ch);
	
	IO_AUDIO.AUDIOIF[ch].AUST.bit.UFIE = 0;
	
	DDIM_User_EnableInt((DDIM_USER_INTID)(E_DD_GIC_INTID_AUDIO_IF_CH0_INT + ch), 14);

	Ddim_Print(("<%s> End. ch=%d\n", __FUNCTION__, ch));
}

