VOID CT_Dd_Audio_ResetTest( UINT8 ch )
{
	INT32 result;
	T_DD_AUDIO_CTRL_COMMON ctrl_common;
	T_DD_AUDIO_CTRL_OUT ctrl_out;
	T_DD_AUDIO_CTRL_IN ctrl_in;
	T_DD_AUDIO_I2S_CMMN i2s_common;
	T_DD_AUDIO_I2S_IN i2s_in;
	T_DD_AUDIO_I2S_OUT i2s_out;
	T_DD_AUDIO_DMA dma_setting;
	
	Ddim_Print(( "<%s> Start\n", __FUNCTION__ ));
	
	ct_dd_audio_reg_init(ch);
	
	result = Dd_Audio_Reset(ch);
	
	if (result != D_DDIM_OK){
		Ddim_Print(("<%s> End. result=0x%x, ch=%d\n", __FUNCTION__, result, ch));
		return;
	}
	
	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	Ddim_Print(("----Dd_Audio_Get_Ctrl_Common----\n"));
	Ddim_Print(("fifo_usage=0x%x\n", ctrl_common.fifo_usage));
	Ddim_Print(("channel=0x%x\n", ctrl_common.channel));
	
	if (ch != 3){
		Dd_Audio_Get_Ctrl_Input(ch, &ctrl_in);
		
		Ddim_Print(("----Dd_Audio_Get_Ctrl_Input----\n"));
		Ddim_Print(("format=0x%x\n", ctrl_in.format));
		Ddim_Print(("fifo_stages=0x%x\n", ctrl_in.fifo_stages));
		Ddim_Print(("ahb_format=0x%x\n", ctrl_in.ahb_format));
		Ddim_Print(("bit_shift=0x%x\n", ctrl_in.bit_shift));
	}
	
	if (ch < 4){
		Dd_Audio_Get_Ctrl_Output(ch, &ctrl_out);
		
		Ddim_Print(("----Dd_Audio_Get_Ctrl_Output----\n"));
		Ddim_Print(("format=0x%x\n", ctrl_out.format));
		Ddim_Print(("fifo_stages=0x%x\n", ctrl_out.fifo_stages));
		Ddim_Print(("ahb_format=0x%x\n", ctrl_out.ahb_format));
		Ddim_Print(("lr_copy=0x%x\n", ctrl_out.lr_copy));
		Ddim_Print(("mix_play=0x%x\n", ctrl_out.mix_play));
		Ddim_Print(("bit_shift=0x%x\n", ctrl_out.bit_shift));
	}
	
	Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
	
	Ddim_Print(("----Dd_Audio_Get_Ctrl_I2sCmmn----\n"));
	Ddim_Print(("aumclki=0x%x\n", i2s_common.aumclki));
	Ddim_Print(("div_aumclko=0x%x\n", i2s_common.div_aumclko));
	Ddim_Print(("div_auclk=0x%x\n", i2s_common.div_auclk));
	Ddim_Print(("div_lrclk=0x%x\n", i2s_common.div_lrclk));
	Ddim_Print(("clk_div_enable=0x%x\n", i2s_common.clk_div_enable));
	Ddim_Print(("master_slave=0x%x\n", i2s_common.master_slave));
	
	if (ch != 3){
		Dd_Audio_Get_Ctrl_I2sIn(ch, &i2s_in);
		
		Ddim_Print(("----Dd_Audio_Get_Ctrl_I2sIn----\n"));
		Ddim_Print(("mode_in=0x%x\n", i2s_in.mode_in));
		Ddim_Print(("bit_in=0x%x\n", i2s_in.bit_in));
	}
	
	if (ch < 4){
		Dd_Audio_Get_Ctrl_I2sOut(ch, &i2s_out);
		
		Ddim_Print(("----Dd_Audio_Get_Ctrl_I2sOut----\n"));
		Ddim_Print(("mode_out=0x%x\n", i2s_out.mode_out));
		Ddim_Print(("bit_out=0x%x\n", i2s_out.bit_out));
		Ddim_Print(("fs=0x%x\n", i2s_out.fs));
	}
	
	if (ch != 3){
		Dd_Audio_Get_Ctrl_DmaIn(ch, &dma_setting);
		
		Ddim_Print(("----Dd_Audio_Get_Ctrl_DmaIn----\n"));
		Ddim_Print(("dma_2ch=0x%x\n", dma_setting.dma_2ch));
		Ddim_Print(("dma_trnsf_cnt=0x%x\n", dma_setting.dma_trnsf_cnt));
	}
	
	if (ch < 4){
		Dd_Audio_Get_Ctrl_DmaOut(ch, &dma_setting);
		
		Ddim_Print(("----Dd_Audio_Get_Ctrl_DmaOut----\n"));
		Ddim_Print(("dma_2ch=0x%x\n", dma_setting.dma_2ch));
		Ddim_Print(("dma_trnsf_cnt=0x%x\n", dma_setting.dma_trnsf_cnt));
	}

	Ddim_Print(("<%s> End. result=0x%x, ch=%d\n", __FUNCTION__, result, ch));
}


