VOID CT_Dd_Audio_Start_LoopBackTest1( UINT8 ch )
{
	T_DD_AUDIO_CTRL_COMMON ctrl_common;
	T_DD_AUDIO_CTRL_IN ctrl_inf_in;
	T_DD_AUDIO_CTRL_OUT ctrl_inf_out;
	T_DD_AUDIO_I2S_CMMN i2s_common;
	T_DD_AUDIO_I2S_IN i2s_in;
	T_DD_AUDIO_I2S_OUT i2s_out;
	INT32 result;
	
	Ddim_Print(( "<%s> Start\n", __FUNCTION__ ));
	
	ct_dd_audio_reg_init(ch);
	
	Dd_Audio_Init();
	
	Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
	i2s_common.master_slave = E_DD_AUDIO_CLK_MASTER;
	i2s_common.clk_div_enable = D_DD_AUDIO_ENABLE;
	Dd_Audio_Ctrl_I2sCmmn(ch, &i2s_common);
	
	Dd_Audio_Get_Ctrl_I2sIn(ch, &i2s_in);
	i2s_in.bit_in = E_DD_AUDIO_BIT_16BIT;
	Dd_Audio_Ctrl_I2sIn(ch, &i2s_in);
	
	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	ctrl_common.fifo_usage = E_DD_AUDIO_FIFO_USAGE_STAGES_16;
	Dd_Audio_Ctrl_Common(ch, &ctrl_common);
	
	Dd_Audio_Get_Ctrl_Input(ch, &ctrl_inf_in);
	(VOID)Dd_Audio_Ctrl_Input(ch, &ctrl_inf_in);
	
	Dd_Audio_Start_Input(ch);
	
//	IO_AUDIO.AUDIOIF[ch].AUCR.bit.AUIEF = 0;
	
#ifdef PC_DEBUG
	IO_AUDIO.AUDIOIF[ch].AUCR.bit.AUIEF = 1;		// for PC-Sim
#endif
	
	Dd_Audio_Get_Ctrl_I2sOut(ch, &i2s_out);
	i2s_out.bit_out = E_DD_AUDIO_BIT_16BIT;
	i2s_out.mode_out = E_DD_AUDIO_MODE_L_JUST;
	i2s_out.fs = E_DD_AUDIO_FS_64FS;
	Dd_Audio_Ctrl_I2sOut(ch, &i2s_out);
	
	Dd_Audio_Get_Ctrl_Output(ch, &ctrl_inf_out);
	ctrl_inf_out.format = E_DD_AUDIO_DATA_REG_FRMT_L_JUST;
	ctrl_inf_out.fifo_stages = E_DD_AUDIO_FIFO_STAGES_1;
	ctrl_inf_out.ahb_format = E_DD_AUDIO_AHB_FRMT_L_JUST;
	Dd_Audio_Ctrl_Output(ch, &ctrl_inf_out);
	
	DDIM_User_Dly_Tsk(0);
	
	result = Dd_Audio_Start_LoopBack(ch);
	
#ifdef PC_DEBUG
	IO_AUDIO.AUDIOIF[ch].AUMD.bit.LBF = 1;
#endif
	
	DDIM_User_Dly_Tsk(0);
	
	Ddim_Print(("AUMD.LBF=0x%x\n", IO_AUDIO.AUDIOIF[ch].AUMD.bit.LBF));
	
	Ddim_Print(("<%s> End. result=0x%x, ch=%d\n", __FUNCTION__, result, ch));
}

