VOID CT_Dd_Audio_Set_SwapHW_AUIDLRTest3( UINT8 ch )
{
	T_DD_AUDIO_CTRL_IN ctrl_inf;
	T_DD_AUDIO_CTRL_COMMON ctrl_common;
	T_DD_AUDIO_I2S_CMMN i2s_common;
	T_DD_AUDIO_I2S_IN i2s_in;
	INT32 result;
	
	Ddim_Print(( "<%s> Start\n", __FUNCTION__ ));
	
	ct_dd_audio_reg_init(ch);
	
	Dd_Audio_Init();
	
	if (ch != 1){
		Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
		i2s_common.master_slave = E_DD_AUDIO_CLK_SLAVE;
		i2s_common.clk_div_enable = D_DD_AUDIO_DISABLE;
		Dd_Audio_Ctrl_I2sCmmn(ch, &i2s_common);
	}
	else {
		Dd_Audio_Get_Ctrl_I2sCmmn(0, &i2s_common);
		i2s_common.master_slave = E_DD_AUDIO_CLK_SLAVE;
		i2s_common.clk_div_enable = D_DD_AUDIO_DISABLE;
		Dd_Audio_Ctrl_I2sCmmn(0, &i2s_common);
		
	}
	
	Dd_Audio_Get_Ctrl_I2sIn(ch, &i2s_in);
	i2s_in.bit_in = E_DD_AUDIO_BIT_16BIT;
	i2s_in.mode_in = E_DD_AUDIO_MODE_R_JUST;
	Dd_Audio_Ctrl_I2sIn(ch, &i2s_in);
	
	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	ctrl_common.fifo_usage = E_DD_AUDIO_FIFO_USAGE_STAGES_8;
	Dd_Audio_Ctrl_Common(ch, &ctrl_common);
	
	Dd_Audio_Get_Ctrl_Input(ch, &ctrl_inf);
	ctrl_inf.format = E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
	ctrl_inf.fifo_stages = E_DD_AUDIO_FIFO_STAGES_1;
	ctrl_inf.ahb_format = E_DD_AUDIO_AHB_FRMT_R_JUST;
	ctrl_inf.bit_shift = E_DD_AUDIO_BIT_SHIFT_0;
	(VOID)Dd_Audio_Ctrl_Input(ch, &ctrl_inf);
	
	Dd_Audio_Set_SwapHW_AUIDLR(ch, D_DD_AUDIO_ENABLE);
	
	if (ch != 1){
		Dd_Audio_Start_Input(ch);
	}
	else {
		Dd_Audio_Get_Ctrl_Common(0, &ctrl_common);
		ctrl_common.fifo_usage = E_DD_AUDIO_FIFO_USAGE_STAGES_8;
		Dd_Audio_Ctrl_Common(0, &ctrl_common);
		
		Dd_Audio_Get_Ctrl_Input(0, &ctrl_inf);
		ctrl_inf.format = E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
		ctrl_inf.fifo_stages = E_DD_AUDIO_FIFO_STAGES_1;
		ctrl_inf.ahb_format = E_DD_AUDIO_AHB_FRMT_R_JUST;
		ctrl_inf.bit_shift = E_DD_AUDIO_BIT_SHIFT_0;
		(VOID)Dd_Audio_Ctrl_Input(0, &ctrl_inf);
		
		Dd_Audio_Start_Input(D_DD_AUDIO_IF_CH0_CH1);
	}
	
#ifdef PC_DEBUG
	if (ch != 1){
		IO_AUDIO.AUDIOIF[ch].AUCR.bit.AUIEF = 1;
	}
	else {
		IO_AUDIO.AUDIOIF[0].AUCR.bit.AUIEF = 1;
		IO_AUDIO.AUDIOIF[1].AUCR.bit.AUIEF = 1;
	}
#endif
	
	result = Dd_Audio_Set_SwapHW_AUIDLR(ch, D_DD_AUDIO_ENABLE);
	
	Ddim_Print(("AUMD.IHW_SWP=0x%x\n", IO_AUDIO.AUDIOIF[ch].AUMD.bit.IHW_SWP));
	
	Ddim_Print(("<%s> End. result=0x%x, ch=%d\n", __FUNCTION__, result, ch));
}

