VOID CT_Dd_Audio_3_UpdateOutputSetting( UINT8 ch )
{
	T_DD_AUDIO_CTRL_COMMON	ctrl_common;
	T_DD_AUDIO_CTRL_OUT	ctrl_out;
	T_DD_AUDIO_I2S_CMMN	i2s_common;
	T_DD_AUDIO_I2S_OUT	i2s_out;
	T_DD_AUDIO_DMA	dma;
	
	ct_dd_audio_test_init();
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Open_Output(ch, D_DDIM_USER_SEM_WAIT_FEVR), D_DDIM_OK);
	
	Dd_Audio_Init();
	
	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	Dd_Audio_Get_Ctrl_Output(ch, &ctrl_out);
	Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
	Dd_Audio_Get_Ctrl_I2sOut(ch, &i2s_out);
	Dd_Audio_Get_Ctrl_DmaOut(ch, &dma);
	
	i2s_common.aumclki = E_DD_AUDIO_MASTER_CLOCK_22_5792;
	i2s_common.div_aumclko =  E_DD_AUDIO_AUMCLKO_DIV_4;
	i2s_common.div_auclk = E_DD_AUDIO_AUCLK_DIV_8;
	i2s_common.div_lrclk = E_DD_AUDIO_AULR_DIV_64;
	i2s_common.clk_div_enable = D_DD_AUDIO_ENABLE;
	i2s_common.master_slave = E_DD_AUDIO_CLK_MASTER;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_I2sCmmn(ch, &i2s_common), D_DDIM_OK);
	
	i2s_out.mode_out = E_DD_AUDIO_MODE_R_JUST;
	i2s_out.bit_out = E_DD_AUDIO_BIT_16BIT;
	i2s_out.fs = E_DD_AUDIO_FS_64FS;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_I2sOut(ch, &i2s_out), D_DDIM_OK);
	
	ctrl_common.fifo_usage = E_DD_AUDIO_FIFO_USAGE_STAGES_4;
	ctrl_common.channel = E_DD_AUDIO_CHANNEL_STEREO;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Common(ch, &ctrl_common), D_DDIM_OK);
	
	ctrl_out.format = E_DD_AUDIO_DATA_REG_FRMT_L_JUST;
	ctrl_out.fifo_stages =  E_DD_AUDIO_FIFO_STAGES_16;
	ctrl_out.ahb_format = E_DD_AUDIO_AHB_FRMT_L_JUST;
	
	if (ch != 1){
		ctrl_out.lr_copy = D_DD_AUDIO_ENABLE;
	}
	else {
		ctrl_out.lr_copy = D_DD_AUDIO_DISABLE;
	}
	
	ctrl_out.mix_play = D_DD_AUDIO_ENABLE;
	ctrl_out.bit_shift = E_DD_AUDIO_BIT_SHIFT_3;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Output(ch, &ctrl_out), D_DDIM_OK);
	
	dma.dma_2ch = D_DD_AUDIO_ENABLE;
	dma.dma_trnsf_cnt = 1024;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_DmaOut(ch, &dma), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	Dd_Audio_Get_Ctrl_Output(ch, &ctrl_out);
	Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
	Dd_Audio_Get_Ctrl_I2sOut(ch, &i2s_out);
	Dd_Audio_Get_Ctrl_DmaOut(ch, &dma);
	
	ct_dd_audio_test_assert_equals(ctrl_common.fifo_usage, E_DD_AUDIO_FIFO_USAGE_STAGES_4);
	ct_dd_audio_test_assert_equals(ctrl_common.channel, E_DD_AUDIO_CHANNEL_STEREO);
	
	ct_dd_audio_test_assert_equals(ctrl_out.format, E_DD_AUDIO_DATA_REG_FRMT_L_JUST);
	ct_dd_audio_test_assert_equals(ctrl_out.fifo_stages,  E_DD_AUDIO_FIFO_STAGES_16);
	ct_dd_audio_test_assert_equals(ctrl_out.ahb_format, E_DD_AUDIO_AHB_FRMT_L_JUST);
	
	if (ch != 1){
		ct_dd_audio_test_assert_equals(ctrl_out.lr_copy, D_DD_AUDIO_ENABLE);
	}
	else {
		ct_dd_audio_test_assert_equals(ctrl_out.lr_copy, D_DD_AUDIO_DISABLE);
	}
	
	ct_dd_audio_test_assert_equals(ctrl_out.mix_play, D_DD_AUDIO_ENABLE);
	ct_dd_audio_test_assert_equals(ctrl_out.bit_shift, E_DD_AUDIO_BIT_SHIFT_3);
	
	if (ch != 1){
		ct_dd_audio_test_assert_equals(i2s_common.aumclki, E_DD_AUDIO_MASTER_CLOCK_22_5792);
		ct_dd_audio_test_assert_equals(i2s_common.div_aumclko, E_DD_AUDIO_AUMCLKO_DIV_4);
		ct_dd_audio_test_assert_equals(i2s_common.div_auclk, E_DD_AUDIO_AUCLK_DIV_8);
		ct_dd_audio_test_assert_equals(i2s_common.div_lrclk, E_DD_AUDIO_AULR_DIV_64);
		ct_dd_audio_test_assert_equals(i2s_common.clk_div_enable, D_DD_AUDIO_ENABLE);
		ct_dd_audio_test_assert_equals(i2s_common.master_slave, E_DD_AUDIO_CLK_MASTER);
	}
	
	ct_dd_audio_test_assert_equals(i2s_out.mode_out, E_DD_AUDIO_MODE_R_JUST);
	ct_dd_audio_test_assert_equals(i2s_out.bit_out, E_DD_AUDIO_BIT_16BIT);
	ct_dd_audio_test_assert_equals(i2s_out.fs, E_DD_AUDIO_FS_64FS);
	
	ct_dd_audio_test_assert_equals(dma.dma_2ch, D_DD_AUDIO_ENABLE);
	ct_dd_audio_test_assert_equals(dma.dma_trnsf_cnt, 1024);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Close_Output(ch), D_DDIM_OK);
	
	ct_dd_audio_test_fin("> audio 5 : updates output setting test", ch);
}


