VOID CT_Dd_Audio_3_StartStopInput( UINT8 ch )
{
	T_DD_AUDIO_CTRL_COMMON	ctrl_common;
	T_DD_AUDIO_CTRL_IN	ctrl_in;
	T_DD_AUDIO_I2S_CMMN	i2s_common;
	T_DD_AUDIO_I2S_IN	i2s_in;
	T_DD_AUDIO_DMA	dma;
	
	ct_dd_audio_test_init();
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Open_Input(ch, D_DDIM_USER_SEM_WAIT_FEVR), D_DDIM_OK);
	
	Dd_Audio_Init();
	
	Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
	
	i2s_common.aumclki = E_DD_AUDIO_MASTER_CLOCK_8_192;
	i2s_common.div_aumclko =  E_DD_AUDIO_AUMCLKO_DIV_2;
	i2s_common.div_auclk = E_DD_AUDIO_AUCLK_DIV_16;
	i2s_common.div_lrclk = E_DD_AUDIO_AULR_DIV_32;
	i2s_common.clk_div_enable = D_DD_AUDIO_ENABLE;
	i2s_common.master_slave = E_DD_AUDIO_CLK_MASTER;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_I2sCmmn(ch, &i2s_common), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_I2sIn(ch, &i2s_in);

	i2s_in.mode_in = E_DD_AUDIO_MODE_L_JUST;
	i2s_in.bit_in = E_DD_AUDIO_BIT_16BIT;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_I2sIn(ch, &i2s_in), D_DDIM_OK);
	
	
	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	
	ctrl_common.fifo_usage	= E_DD_AUDIO_FIFO_USAGE_STAGES_8;
	ctrl_common.channel		= E_DD_AUDIO_CHANNEL_MONO;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Common(ch, &ctrl_common), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_Input(ch, &ctrl_in);
	
	ctrl_in.format		= E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
	ctrl_in.fifo_stages	= E_DD_AUDIO_FIFO_STAGES_16;
	ctrl_in.ahb_format	= E_DD_AUDIO_AHB_FRMT_R_JUST;
	ctrl_in.bit_shift	= E_DD_AUDIO_BIT_SHIFT_0;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Input(ch, &ctrl_in), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_DmaIn(ch, &dma);
	
	dma.dma_2ch			= D_DD_AUDIO_DISABLE;
	dma.dma_trnsf_cnt	= 0;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_DmaIn(ch, &dma), D_DDIM_OK);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Start_Input(ch), D_DDIM_OK);
	
	DDIM_User_Dly_Tsk(1);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Get_Status_Input(ch), TRUE);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Stop_Input(ch), D_DDIM_OK);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Get_Status_Input(ch), FALSE);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Close_Input(ch), D_DDIM_OK);
	
	ct_dd_audio_test_fin("> audio 7 : Input start/stop test", ch);
}

