VOID CT_Dd_Audio_3_049(VOID)
{
	UINT8 ch = 0;
	T_DD_AUDIO_CTRL_COMMON	ctrl_common;
	T_DD_AUDIO_CTRL_OUT	ctrl_out;
	T_DD_AUDIO_I2S_CMMN	i2s_common;
	T_DD_AUDIO_I2S_OUT	i2s_out;
	T_DD_AUDIO_DMA	dma;

	ct_dd_audio_test_init();

	ct_dd_audio_test_assert_equals(Dd_Audio_Open_Output(ch, D_DDIM_USER_SEM_WAIT_FEVR), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Open_Output(1, D_DDIM_USER_SEM_WAIT_FEVR), D_DDIM_OK);

	if(Dd_HDMAC0_Open(0, D_DDIM_USER_SEM_WAIT_FEVR) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Open Error(ch0)\n"));
	}
	if(Dd_HDMAC0_Open(1, D_DDIM_USER_SEM_WAIT_FEVR) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Open Error(ch1)\n"));
	}
	if(Dd_HDMAC0_Open(2, D_DDIM_USER_SEM_WAIT_FEVR) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Open Error(ch2)\n"));
	}
	if(Dd_HDMAC0_Open(3, D_DDIM_USER_SEM_WAIT_FEVR) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Open Error(ch3)\n"));
	}
	
	Dd_Audio_Init();
	
	Dd_Audio_Get_Ctrl_I2sCmmn(ch, &i2s_common);
	
	i2s_common.aumclki = E_DD_AUDIO_MASTER_CLOCK_8_192;
	i2s_common.div_aumclko =  E_DD_AUDIO_AUMCLKO_DIV_4;
	i2s_common.div_auclk = E_DD_AUDIO_AUCLK_DIV_4;
	i2s_common.div_lrclk = E_DD_AUDIO_AULR_DIV_64;
	i2s_common.clk_div_enable = D_DD_AUDIO_ENABLE;
	i2s_common.master_slave = E_DD_AUDIO_CLK_MASTER;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_I2sCmmn(ch, &i2s_common), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_I2sOut(ch, &i2s_out);
	
	i2s_out.mode_out = E_DD_AUDIO_MODE_L_JUST;
	i2s_out.bit_out = E_DD_AUDIO_BIT_16BIT;
	i2s_out.fs = E_DD_AUDIO_FS_64FS;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_I2sOut(ch, &i2s_out), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	
	ctrl_common.fifo_usage	= E_DD_AUDIO_FIFO_USAGE_STAGES_1;
	ctrl_common.channel		= E_DD_AUDIO_CHANNEL_STEREO;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Common(ch, &ctrl_common), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_Common(1, &ctrl_common);
	
	ctrl_common.fifo_usage	= E_DD_AUDIO_FIFO_USAGE_STAGES_1;
	ctrl_common.channel		= E_DD_AUDIO_CHANNEL_STEREO;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Common(1, &ctrl_common), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_Output(ch, &ctrl_out);
	
	ctrl_out.format = E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
	ctrl_out.fifo_stages =  E_DD_AUDIO_FIFO_STAGES_16;
	ctrl_out.ahb_format = E_DD_AUDIO_AHB_FRMT_R_JUST;
	ctrl_out.lr_copy = D_DD_AUDIO_DISABLE;
	ctrl_out.mix_play = D_DD_AUDIO_DISABLE;
	ctrl_out.bit_shift = E_DD_AUDIO_BIT_SHIFT_0;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Output(ch, &ctrl_out), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_Output(1, &ctrl_out);
	
	ctrl_out.format = E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
	ctrl_out.fifo_stages =  E_DD_AUDIO_FIFO_STAGES_16;
	ctrl_out.ahb_format = E_DD_AUDIO_AHB_FRMT_R_JUST;
	ctrl_out.lr_copy = D_DD_AUDIO_DISABLE;
	ctrl_out.mix_play = D_DD_AUDIO_DISABLE;
	ctrl_out.bit_shift = E_DD_AUDIO_BIT_SHIFT_0;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Output(1, &ctrl_out), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_DmaOut(ch, &dma);
	
	dma.dma_2ch			= D_DD_AUDIO_ENABLE;
	dma.dma_trnsf_cnt	= 800;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_DmaOut(ch, &dma), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_DmaOut(1, &dma);
	
	dma.dma_2ch			= D_DD_AUDIO_ENABLE;
	dma.dma_trnsf_cnt	= 800;
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_DmaOut(1, &dma), D_DDIM_OK);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_SwapHW_AUODLR(ch, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_SwapHW_AUODLR(1, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	
	dd_ct_audio_DMA_Int_Cnt = 0;
	dd_ct_audio_DMA_Int_Cnt1 = 0;
	Dd_HDMAC0_Output_Audio_Async (0,
								 D_DD_HDMAC0_IS_IDREQ_1,
								 CT_DD_Audio_WORK_AREA,
								 Dd_Audio_Get_Addr_Reg_AUODLR(ch),
								 (800*2*2),
								 (VP_CALLBACK)ct_dd_audio_DMA_Int_Handler049_0);
	
	dd_ct_audio_DMA_Int_Cnt++;
	Dd_HDMAC0_Output_Audio_Async(1,
								 D_DD_HDMAC0_IS_IDREQ_13,
								 CT_DD_Audio_WORK_AREA+(800*2*2*dd_ct_audio_DMA_Int_Cnt),
								 Dd_Audio_Get_Addr_Reg_AUODLR(ch),
								 (800*2*2),
								 (VP_CALLBACK)ct_dd_audio_DMA_Int_Handler049_1);
	
	Dd_HDMAC0_Output_Audio_Async (2,
								 D_DD_HDMAC0_IS_IDREQ_3,
								 CT_DD_Audio_WORK_AREA2,
								 Dd_Audio_Get_Addr_Reg_AUODLR(1),
								 (800*2*2),
								 (VP_CALLBACK)ct_dd_audio_DMA_Int_Handler049_2);
	
	dd_ct_audio_DMA_Int_Cnt1++;
	Dd_HDMAC0_Output_Audio_Async(3,
								 D_DD_HDMAC0_IS_IDREQ_15,
								 CT_DD_Audio_WORK_AREA2+(800*2*2*dd_ct_audio_DMA_Int_Cnt1),
								 Dd_Audio_Get_Addr_Reg_AUODLR(1),
								 (800*2*2),
								 (VP_CALLBACK)ct_dd_audio_DMA_Int_Handler049_3);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_OutputDMARequestEnable(ch, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_OutputDMARequestEnable(1, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Start_Output(D_DD_AUDIO_IF_CH0_CH1), D_DDIM_OK);
	
	DDIM_User_Dly_Tsk(1200);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_OutputDMARequestEnable(ch, D_DD_AUDIO_DISABLE), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_OutputDMARequestEnable(1, D_DD_AUDIO_DISABLE), D_DDIM_OK);
	
	if(Dd_HDMAC0_Stop(0) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch0)\n"));
	}

	if(Dd_HDMAC0_Stop(1) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch1)\n"));
	}
	
	if(Dd_HDMAC0_Stop(2) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch2)\n"));
	}

	if(Dd_HDMAC0_Stop(3) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch3)\n"));
	}
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Stop_Output(D_DD_AUDIO_IF_CH0_CH1), D_DDIM_OK);
	
	Dd_HDMAC0_Close(0);
	Dd_HDMAC0_Close(1);
	Dd_HDMAC0_Close(2);
	Dd_HDMAC0_Close(3);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Close_Output(ch), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Close_Output(1), D_DDIM_OK);
	
	ct_dd_audio_test_fin("> audio 49 : Play(1000ms) DMA 2ch mode test",ch);
}

