	i2s_common.div_auclk = E_DD_AUDIO_AUCLK_DIV_4;
	i2s_common.div_lrclk = E_DD_AUDIO_AULR_DIV_64;
	i2s_common.clk_div_enable = D_DD_AUDIO_ENABLE;
	i2s_common.master_slave = E_DD_AUDIO_CLK_MASTER;
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_I2sCmmn(2, &i2s_common), D_DDIM_OK);

	Dd_Audio_Get_Ctrl_Common(ch, &ctrl_common);
	ctrl_common.fifo_usage	= E_DD_AUDIO_FIFO_USAGE_STAGES_8;
	ctrl_common.channel		= E_DD_AUDIO_CHANNEL_STEREO;
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Common(ch, &ctrl_common), D_DDIM_OK);

	Dd_Audio_Get_Ctrl_Input(ch, &ctrl_in);
	ctrl_in.format		= E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
	ctrl_in.fifo_stages	= E_DD_AUDIO_FIFO_STAGES_16;
	ctrl_in.ahb_format	= E_DD_AUDIO_AHB_FRMT_R_JUST;
	ctrl_in.bit_shift	= E_DD_AUDIO_BIT_SHIFT_0;
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Input(ch, &ctrl_in), D_DDIM_OK);

	Dd_Audio_Get_Ctrl_Output(ch, &ctrl_out);
	ctrl_out.format = E_DD_AUDIO_DATA_REG_FRMT_R_JUST;
	ctrl_out.fifo_stages =  E_DD_AUDIO_FIFO_STAGES_16;
	ctrl_out.ahb_format = E_DD_AUDIO_AHB_FRMT_R_JUST;
	ctrl_out.lr_copy = D_DD_AUDIO_DISABLE;
	ctrl_out.mix_play = D_DD_AUDIO_DISABLE;
	ctrl_out.bit_shift = E_DD_AUDIO_BIT_SHIFT_0;
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_Output(ch, &ctrl_out), D_DDIM_OK);

	Dd_Audio_Get_Ctrl_DmaIn(ch, &dma);
	dma.dma_2ch			= D_DD_AUDIO_ENABLE;
	dma.dma_trnsf_cnt	= 400;
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_DmaIn(ch, &dma), D_DDIM_OK);
	
	Dd_Audio_Get_Ctrl_DmaOut(ch, &dma);
	dma.dma_2ch			= D_DD_AUDIO_ENABLE;
	dma.dma_trnsf_cnt	= 400;
	ct_dd_audio_test_assert_equals(Dd_Audio_Ctrl_DmaOut(ch, &dma), D_DDIM_OK);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_SwapHW_AUIDLR(ch, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_SwapHW_AUODLR(ch, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	
	dd_ct_audio_DMA_Int_Cnt_In = 0;
	
	Dd_HDMAC0_Input_Audio_Async(0,
								D_DD_HDMAC0_IS_IDREQ_0,
								Dd_Audio_Get_Addr_Reg_AUIDLR(ch),
								CT_DD_Audio_WORK_AREA2,
								(800*2*2),
								(VP_CALLBACK)ct_dd_audio_DMA_Int_Handler125_In_0);

	dd_ct_audio_DMA_Int_Cnt_In++;

	Dd_HDMAC0_Input_Audio_Async(1,
								D_DD_HDMAC0_IS_IDREQ_12,
								Dd_Audio_Get_Addr_Reg_AUIDLR(ch),
								CT_DD_Audio_WORK_AREA2+(800*2*2),
								(800*2*2),
								(VP_CALLBACK)ct_dd_audio_DMA_Int_Handler125_In_1);

	dd_ct_audio_DMA_Int_Cnt_Out = 0;
	Dd_HDMAC0_Output_Audio_Async(2,
								D_DD_HDMAC0_IS_IDREQ_1,
								CT_DD_Audio_WORK_AREA,
								Dd_Audio_Get_Addr_Reg_AUODLR(ch),
								(800*2*2),
								(VP_CALLBACK)ct_dd_audio_DMA_Int_Handler125_Out_0);

	dd_ct_audio_DMA_Int_Cnt_Out++;
	Dd_HDMAC0_Output_Audio_Async(3,
								D_DD_HDMAC0_IS_IDREQ_13,
								CT_DD_Audio_WORK_AREA+(800*2*2),
								Dd_Audio_Get_Addr_Reg_AUODLR(ch),
								(800*2*2),
								(VP_CALLBACK)ct_dd_audio_DMA_Int_Handler125_Out_1);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_InputDMARequestEnable(ch, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_OutputDMARequestEnable(ch, D_DD_AUDIO_ENABLE), D_DDIM_OK);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Start_Output(ch), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Start_Input(ch), D_DDIM_OK);
	
	DDIM_User_Dly_Tsk(1500);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Stop_Input(ch), D_DDIM_OK);

	ct_dd_audio_test_assert_equals(Dd_Audio_Set_InputDMARequestEnable(ch, D_DD_AUDIO_DISABLE), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Set_OutputDMARequestEnable(ch, D_DD_AUDIO_DISABLE), D_DDIM_OK);
	
	if(Dd_HDMAC0_Stop(0) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch0)\n"));
	}
	if(Dd_HDMAC0_Stop(1) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch0)\n"));
	}
	if(Dd_HDMAC0_Stop(2) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch2)\n"));
	}
	if(Dd_HDMAC0_Stop(3) != D_DDIM_OK) {
		Ddim_Print(("Dd_HDMAC0_Stop Error(ch3)\n"));
	}
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Stop_Output(ch), D_DDIM_OK);
	
	Dd_HDMAC0_Close(0);
	Dd_HDMAC0_Close(1);

	Dd_HDMAC0_Close(2);
	
	ct_dd_audio_test_assert_equals(Dd_Audio_Close_Input(ch), D_DDIM_OK);
	ct_dd_audio_test_assert_equals(Dd_Audio_Close_Output(ch), D_DDIM_OK);
	
