static VOID ct_dd_audio_DMA_Int_HandlerFifoMonitor_Play0( VOID )
{
	UINT8 ch = 0;
	
	dd_ct_audio_DMA_Int_Cnt++;
	if(dd_ct_audio_DMA_Int_Cnt < 5) {
		
		Dd_HDMAC0_Output_Audio_Async(2,
									 D_DD_HDMAC0_IS_IDREQ_1,
									 CT_DD_Audio_WORK_AREA+(256*4*dd_ct_audio_DMA_Int_Cnt),
									 Dd_Audio_Get_Addr_Reg_AUODLR(ch),
									 (256*4),
									 (VP_CALLBACK)ct_dd_audio_DMA_Int_HandlerFifoMonitor_Play0);
		
		if (IO_AUDIO.AUDIOIF[ch].AUST.bit.ORUF == 1){
			Ddim_Print(("underflow\n"));
		}
	}
	
	Ddim_Print(("ct_dd_audio_DMA_Int_HandlerFifoMonitor_Play0\n"));
}

