VOID CT_Dd_Audio_bit_shift( UINT16* pcm, UINT32 data_bytes )
{
	UINT32 loop;
	
	for (loop = 0; loop < (data_bytes / 2); loop++){
		*pcm = (*pcm) << 1;
		pcm++;
	}
}

